import React, { useState } from 'react';
import './Components.css';

/* CertificatesCard
   Displays a list of course certificates with:
   - Course title
   - Toggle to preview certificate image
   - Optional external verification link
*/

const certificateData = [
  {
    id: 'unity-mastery',
    title: 'Complete C# Unity Game Developer 2D',
    provider: 'Udemy',
    image: '/certificates/udemy-placeholder.svg',
    verifyUrl: null
  },
  {
    id: 'unreal-blueprints',
    title: 'Unreal Engine 5 Blueprints Developer',
    provider: 'Udemy',
    image: '/certificates/udemy-placeholder.svg',
    verifyUrl: null
  }
];

const CertificatesCard = () => {
  const [openId, setOpenId] = useState(null);

  const toggle = (id) => setOpenId(prev => prev === id ? null : id);

  return (
    <div className="awards-card certificates-card">
      <h3 style={{marginTop:0, textAlign:'center', fontSize:'1.25rem'}}>Course Certificates</h3>
      <div className="cert-list">
        {certificateData.map(cert => (
          <div key={cert.id} className={`cert-entry ${openId === cert.id ? 'open' : ''}`}>
            <button className="cert-toggle" onClick={() => toggle(cert.id)} aria-expanded={openId === cert.id}>
              <span className="cert-title">{cert.title}</span>
              <span className="cert-indicator">{openId === cert.id ? '−' : '+'}</span>
            </button>
            <div className="cert-panel" style={{maxHeight: openId === cert.id ? '520px' : '0'}}>
              <div className="cert-inner">
                <p className="cert-provider"><strong>Provider:</strong> {cert.provider}</p>
                {cert.verifyUrl && (
                  <p className="cert-verify"><a href={cert.verifyUrl} target="_blank" rel="noopener noreferrer">Verify Online</a></p>
                )}
                {cert.image && (
                  <div className="cert-image-wrapper">
                    <img src={cert.image} alt={cert.title + ' certificate'} loading="lazy" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        {certificateData.length === 0 && (
          <p className="cert-empty">No certificates added yet.</p>
        )}
      </div>
    </div>
  );
};

export default CertificatesCard;
